import org.owasp.encoder.Encode;

public class SecureXSSExample {
    public static void main(String[] args) {
        // Simulating user input being read from an untrusted source
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Sanitize and encode user input using OWASP Java Encoder library
        String sanitizedUserInput = Encode.forHtml(userInput);

        // Properly handle user input with sanitized and encoded output
        String output = "Welcome, " + sanitizedUserInput;

        System.out.println(output);
    }
}

